"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[19537],{20481(e,n,t){t.r(n),t.d(n,{assets:()=>s,contentTitle:()=>c,default:()=>l,frontMatter:()=>o,metadata:()=>r,toc:()=>u});let r=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 17 and IAS 21/multi-currency-groups-of-insurance-c-7eba702cb6","title":"Multi-currency Groups of Insurance Contracts (IFRS 17 and IAS 21)","description":"October 2022","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 17 and IAS 21/Multi-currency Groups of Insurance Contracts (IFRS 17 and IAS 21).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 17 and IAS 21","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-and-ias-21-6f301e9ffb/multi-currency-groups-of-insurance-c-7eba702cb6","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-and-ias-21-6f301e9ffb/multi-currency-groups-of-insurance-c-7eba702cb6","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"multi-currency-groups-of-insurance-c-7eba702cb6","title":"Multi-currency Groups of Insurance Contracts (IFRS 17 and IAS 21)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-and-ias-21-6f301e9ffb/multi-currency-groups-of-insurance-c-7eba702cb6","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Transfer of Insurance Coverage under a Group of Annuity Contracts (IFRS 17)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-insurance-contracts-e123436304/transfer-of-insurance-coverage-under-15cb0d63cc"},"next":{"title":"Special Purpose Acquisition Companies (SPAC)\uFF1AAccounting for Warrants at Acquisition","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-2-and-ias-32-56a750466e/special-purpose-acquisition-companie-b7f4772d91"}}');var i=t(74848),a=t(28453);let o={id:"multi-currency-groups-of-insurance-c-7eba702cb6",title:"Multi-currency Groups of Insurance Contracts (IFRS 17 and IAS 21)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-and-ias-21-6f301e9ffb/multi-currency-groups-of-insurance-c-7eba702cb6",sidebar_position:1},c,s={},u=[];function d(e){let n={p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.p,{children:"October 2022"}),"\n",(0,i.jsx)(n.p,{children:"The Committee received a request about how an entity accounts for insurance contracts with cash flows in more than one currency."}),"\n",(0,i.jsx)(n.p,{children:"The request asked:\na. whether an entity considers currency exchange rate risks when applying IFRS 17 to identify portfolios of insurance contracts; and\nb. how an entity applies IAS 21 in conjunction with IFRS 17 in measuring a group of insurance contracts with cash flows in more than one currency (a multi-currency group of insurance contracts)."}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Identifying portfolios of insurance contracts"}),"\nIFRS 17 requires an entity to recognise and measure groups of insurance contracts. The first step in establishing groups of insurance contracts is to identify portfolios of insurance contracts. Paragraph 14 of IFRS 17 states that \u2018a portfolio comprises contracts subject to similar risks and managed together\u2019. The request asks whether currency exchange rate risks are among the risks an entity considers when assessing whether insurance contracts are \u2018subject to similar risks\u2019."]}),"\n",(0,i.jsx)(n.p,{children:"IFRS 17 defines financial risk and insurance risk (a non-financial risk). Financial risk is defined to include \u2018the risk of a possible future change in \u2026 [a] currency exchange rate\u2019. When IFRS 17 requires an entity to consider or reflect only particular types of risk (for example, only non-financial risk), it explicitly refers to the risks to be considered or reflected."}),"\n",(0,i.jsx)(n.p,{children:"Therefore, the Committee concluded that, because paragraph 14 of IFRS 17 refers to \u2018similar risks\u2019 without specifying any particular types of risk, an entity is required to consider all risks\u2014including currency exchange rate risks\u2014when identifying portfolios of insurance contracts. However, \u2018similar risks\u2019 does not mean \u2018identical risks\u2019. Therefore, an entity could identify portfolios of contracts that include contracts subject to different currency exchange rate risks. The Committee observed that what an entity considers to be \u2018similar risks\u2019 will depend on the nature and extent of the risks in the entity\u2019s insurance contracts."}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Measuring a multi-currency group of insurance contracts"}),"\nAn entity measures a group of insurance contracts at the total of the fulfilment cash flows and the contractual service margin. Paragraph 30 of IFRS 17 states that \u2018when applying IAS 21 \u2026 to a group of insurance contracts that generate cash flows in a foreign currency, an entity shall treat the group of contracts, including the contractual service margin, as a monetary item\u2019."]}),"\n",(0,i.jsx)(n.p,{children:"Paragraph 8 of IAS 21 defines monetary items as \u2018units of currency held and assets and liabilities to be received or paid in a fixed or determinable number of units of currency\u2019\nand paragraph 20 describes a foreign currency transaction as \u2018a transaction that is denominated or requires settlement in a foreign currency\u2019. Paragraphs 21\u201324 of IAS 21 require an entity:"}),"\n",(0,i.jsx)(n.p,{children:"a. to recognise on initial recognition a foreign currency transaction in the functional currency at the spot exchange rate at the date of the transaction;\nb. to determine the carrying amount of a monetary item in conjunction with other relevant IFRS Accounting Standards; and\nc. to translate at the end of the reporting period foreign currency monetary items into the functional currency using the closing rate."}),"\n",(0,i.jsx)(n.p,{children:"The requirements in both IFRS 17 and IAS 21 refer to transactions or items that are denominated or require settlement in a single currency. IFRS Accounting Standards include no explicit requirements on how to determine the currency denomination of transactions or items with cash flows in more than one currency."}),"\n",(0,i.jsx)(n.p,{children:"Therefore, the Committee observed that, in measuring a multi-currency group of insurance contracts, an entity:"}),"\n",(0,i.jsx)(n.p,{children:"a. applies all the measurement requirements in IFRS 17 to the group of insurance contracts, including the requirement in paragraph 30 to treat the group\u2014including the  contractual service margin\u2014as a monetary item.\nb. applies IAS 21 to translate at the end of the reporting period the carrying amount of the group\u2014including the contractual service margin\u2014into the entity\u2019s functional currency at the closing rate (or rates).\nc. uses its judgement to develop and apply an accounting policy that determines on initial recognition the currency or currencies in which the group\u2014including the contractual service margin\u2014is denominated (currency denomination). The entity could determine that the group\u2014including the contractual service margin\u2014is denominated in a single currency or in the multiple currencies of the cash flows in the group."}),"\n",(0,i.jsx)(n.p,{children:"The entity develops an accounting policy on currency denomination that results in information that is relevant and reliable (as described in paragraph 10 of IAS 8 Accounting Policies, Changes in Accounting Estimates and Errors) and is applied consistently for similar transactions, other events and conditions (paragraph 13 of IAS 8). The accounting policy\nis developed based on the entity\u2019s specific circumstances and the terms of the contracts in the group. The entity cannot simply presume that the contractual service margin for\nthe group is denominated in the functional currency. Such a presumption would, in effect, fail to treat the contractual service margin as a monetary item as required by paragraph 30 of IFRS 17."}),"\n",(0,i.jsx)(n.p,{children:"Single-currency denomination versus multi-currency denomination\nThe entity\u2019s accounting policy on currency denomination determines which effects of changes in exchange rates are changes in financial risk accounted for applying IFRS 17\nand which of these effects are exchange differences accounted for applying IAS 21."}),"\n",(0,i.jsx)(n.p,{children:"A single-currency denomination treats:\na. changes in exchange rates between the currency of the cash flows and the currency of the group of contracts as changes in financial risk that an entity accounts for applying IFRS 17; and\nb. changes in exchange rates between the currency of the group of contracts and the functional currency as exchange differences that an entity accounts for applying IAS 21."}),"\n",(0,i.jsx)(n.p,{children:"A multi-currency denomination treats all changes in exchange rates as exchange differences that an entity accounts for applying IAS 21."}),"\n",(0,i.jsx)(n.p,{children:"In applying IFRS 17, there is a single contractual service margin for the group of insurance contracts. Appendix A to IFRS 17 defines the contractual service margin as representing \u2018the unearned profit the entity will recognise as it provides insurance contract services under the insurance contracts in the group.\u2019 Accordingly, under a multi-currency  enomination, the entity would:"}),"\n",(0,i.jsx)(n.p,{children:"a. assess whether the group of contracts is onerous considering the contractual service margin as a single amount.\nb. prevent the carrying amount of the contractual service margin being negative by, when necessary to do so, recognising a loss.\nc. determine the amount of the contractual service margin to recognise in profit or loss by applying a single method of determining the coverage units provided in the current period and expected to be provided in the future to the amounts denominated in the multiple currencies. This would result in the entity allocating each of the currency amounts of the contractual service margin translated into the functional currency equally to each coverage unit."}),"\n",(0,i.jsxs)(n.p,{children:[(0,i.jsx)(n.strong,{children:"Conclusion"}),"\nIn the light of its analysis, the Committee considered whether to add to the work plan a standard-setting project on how to account for the foreign currency aspects of insurance\ncontracts. The Committee observed that it has not obtained evidence that such a project would be sufficiently narrow in scope that the International Accounting Standards Board\n(IASB) or the Committee could address it in an efficient manner. Consequently, the Committee decided not to add a standard-setting project to the work plan."]})]})}function l(e={}){let{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},28453(e,n,t){t.d(n,{R:()=>o,x:()=>c});var r=t(96540);let i={},a=r.createContext(i);function o(e){let n=r.useContext(a);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function c(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:o(e.components),r.createElement(a.Provider,{value:n},e.children)}}}]);